import graphene
from ariadne import QueryType, ObjectType, make_executable_schema
from ariadne.constants import PLAYGROUND_HTML
from flask import Flask, request, jsonify
from flask_ariadne import AriadneBlueprint

app = Flask(__name__)
bp = AriadneBlueprint('graphql', __name__, route_prefix='/graphql')

class Query(graphene.ObjectType):
    user = graphene.Field(User)

    def resolve_user(self, info):
        return User(username='john_doe', bio='This is a bio.')

class User(ObjectType):
    username = graphene.String()
    bio = graphene.String()

    email = graphene.String()
    phone = graphene.String()
    address = graphene.String()

    @staticmethod
    def resolve_email(root, info):
        if info.context.get('current_user') == root:
            return 'john@example.com'
        else:
            raise Exception('Forbidden')

    @staticmethod
    def resolve_phone(root, info):
        if info.context.get('current_user') == root:
            return '1234567890'
        else:
            raise Exception('Forbidden')

    @staticmethod
    def resolve_address(root, info):
        if info.context.get('current_user') == root:
            return '123 Main St'
        else:
            raise Exception('Forbidden')

class Mutation(graphene.ObjectType):
    pass

schema = make_executable_schema(query=Query)

@bp.route('/', methods=['GET'])
def playground():
    return PLAYGROUND_HTML, 200

@bp.route('/', methods=['POST'])
def resolve_query():
    data = request.get_json()
    success, result = schema.execute(data['query'], context_value={'current_user': 'john_doe'})
    if success:
        return jsonify(graphene.json.dumps(result))
    else:
        return jsonify(graphene.json.dumps({'errors': [str(e) for e in result.errors]})), 400

if __name__ == '__main__':
    app.register_blueprint(bp)
    app.run(debug=True)